**Refactored & Clean Code**

```python
from dataclasses import dataclass
from enum import Enum
from typing import Any, Dict, List, Union
import json
from pathlib import Path


class ProcessingMode(Enum):
    FAST = "fast"
    CAREFUL = "careful"


class OutputFormat(Enum):
    RAW = "raw"
    JSON = "json"
    CSV = "csv"


class ItemType(Enum):
    A = "A"
    B = "B"
    UNKNOWN = "UNKNOWN"


class Status(Enum):
    HIGH = "high"
    NORMAL = "normal"
    ADJUSTED = "adjusted"
    DISCOUNTED = "discounted"
    VALIDATED = "validated"
    ERROR = "error"
    SKIPPED = "skip"


@dataclass(frozen=True)
class ProcessingConfig:
    """Immutable configuration for the processor."""
    mode: ProcessingMode
    flag1: bool = False
    flag2: bool = True
    output_format: OutputFormat = OutputFormat.JSON


@dataclass
class ProcessedItem:
    """Domain model for a processed item."""
    id: str
    val: float
    status: Status


class ItemProcessor:
    """Pure business logic for processing a single item."""

    def __init__(self, config: ProcessingConfig):
        self.config = config

    def process(self, item: Dict[str, Any]) -> ProcessedItem:
        if self.config.mode == ProcessingMode.FAST:
            return self._process_fast(item)
        else:  # CAREFUL
            return self._process_careful(item)

    def _process_fast(self, item: Dict[str, Any]) -> ProcessedItem:
        item_id = item.get("id", "unknown")
        item_type = ItemType(item.get("type") or ItemType.UNKNOWN.value)
        raw_value = item.get("value", 0)

        if item_type == ItemType.A:
            return self._process_type_a(item_id, raw_value)
        elif item_type == ItemType.B:
            return self._process_type_b(item_id, raw_value)
        else:
            return self._process_unknown_fast(item_id)

    def _process_type_a(self, item_id: str, raw_value: Any) -> ProcessedItem:
        multiplier = 1.1 if self.config.flag1 else 1.0
        val = float(raw_value) * multiplier

        if val > 100:
            if self.config.flag2:
                return ProcessedItem(item_id, val, Status.HIGH)
            else:
                return ProcessedItem(item_id, val * 0.9, Status.ADJUSTED)
        return ProcessedItem(item_id, val, Status.NORMAL)

    def _process_type_b(self, item_id: str, raw_value: Any) -> ProcessedItem:
        val = float(raw_value) * 0.95
        return ProcessedItem(item_id, val, Status.DISCOUNTED)

    def _process_unknown_fast(self, item_id: str) -> ProcessedItem:
        if self.config.flag1 and self.config.flag2:
            return ProcessedItem(item_id, 0.0, Status.SKIPPED)
        # Default behavior for unknown items when flags don't match
        return ProcessedItem(item_id, 0.0, Status.NORMAL)

    def _process_careful(self, item: Dict[str, Any]) -> ProcessedItem:
        item_id = item.get("id", "unknown")
        try:
            val = float(item.get("value", 0))
            if val < 0:
                raise ValueError("Negative values are not allowed")
            return ProcessedItem(item_id, val, Status.VALIDATED)
        except (ValueError, TypeError):
            return ProcessedItem(item_id, 0.0, Status.ERROR)


class ResultFormatter:
    """Responsible for formatting processed results."""

    @staticmethod
    def format(results: List[ProcessedItem], output_format: OutputFormat) -> Union[List[Dict], str]:
        if output_format == OutputFormat.RAW:
            return [ResultFormatter._to_dict(item) for item in results]

        if output_format == OutputFormat.JSON:
            return json.dumps([ResultFormatter._to_dict(item) for item in results], indent=2)

        if output_format == OutputFormat.CSV:
            lines = ["id,val,status"] + [
                f"{item.id},{item.val},{item.status.value}" for item in results
            ]
            return "\n".join(lines)

        raise ValueError(f"Unknown output format: {output_format}")

    @staticmethod
    def _to_dict(item: ProcessedItem) -> Dict[str, Any]:
        return {
            "id": item.id,
            "val": item.val,
            "status": item.status.value
        }


class DataProcessor:
    """High-level orchestrator - coordinates processing and formatting."""

    def __init__(self, config: ProcessingConfig):
        self.config = config
        self.processor = ItemProcessor(config)

    def process(self, data: List[Dict[str, Any]]) -> Union[List[Dict], str]:
        if not isinstance(data, list):
            raise TypeError("Input data must be a list of dictionaries")

        results: List[ProcessedItem] = []
        for item in data:
            processed = self.processor.process(item)
            results.append(processed)

        return ResultFormatter.format(results, self.config.output_format)


# =============== Factory for convenience ===============

def create_processor(
    mode: str = "fast",
    flag1: bool = False,
    flag2: bool = True,
    output_type: str = "json"
) -> DataProcessor:
    """Factory function to maintain backward-compatible interface."""
    mode_enum = ProcessingMode.FAST if mode == "fast" else ProcessingMode.CAREFUL
    output_enum = OutputFormat(output_type.lower())

    config = ProcessingConfig(
        mode=mode_enum,
        flag1=flag1,
        flag2=flag2,
        output_format=output_enum
    )
    return DataProcessor(config)


# =============== Public API (maintains original signature) ===============

def process(data, mode, flag1=False, flag2=True, output_type='json'):
    """Original function signature preserved for backward compatibility."""
    processor = create_processor(mode, flag1, flag2, output_type)
    return processor.process(data)
```

---

### Design Decisions Explained

#### 1. **Separation of Concerns**
* **`ItemProcessor`**: Pure business logic per item
* **`ResultFormatter`**: All output formatting logic
* **`DataProcessor`**: Orchestration and validation
* **`ProcessingConfig`**: Immutable configuration (prevents accidental mutation)

#### 2. **Domain Modeling with Enums & Data Classes**
* `Enum`s for `Mode`, `Status`, `OutputFormat`, `ItemType` → eliminates magic strings
* `dataclass` for `ProcessedItem` → clear data contract, immutable where possible
* `ProcessingConfig` is frozen → thread-safe and prevents bugs

#### 3. **Single Responsibility Principle**
Each class has one clear responsibility. This makes testing trivial.

#### 4. **Testability**
* All logic is in small, focused methods
* `ItemProcessor` can be tested in isolation
* `ResultFormatter` can be tested independently
* No side effects in business logic

#### 5. **Type Safety & Documentation**
* Full type hints
* Clear docstrings
* Self-documenting code through proper naming

#### 6. **Backward Compatibility**
* The original `process()` function signature is preserved
* Existing callers continue to work unchanged

#### 7. **Error Handling Strategy**
* Explicit `try/except` only where needed (in "careful" mode)
* Clear error messages
* Graceful degradation

#### 8. **Extensibility**
* Easy to add new item types (just add to `ItemType` and `_process_fast`)
* Easy to add new output formats
* Easy to add new processing modes

#### 9. **Immutability Where It Matters**
* `ProcessingConfig` is frozen
* `ProcessedItem` could easily be made frozen too

---

### Example Usage (New Clean API)

```python
# New clean API
config = ProcessingConfig(
    mode=ProcessingMode.CAREFUL,
    flag1=True,
    output_format=OutputFormat.JSON
)

processor = DataProcessor(config)
result = processor.process(data)

# Or using factory
processor = create_processor("fast", flag1=True, output_type="csv")
result = processor.process(data)
```

### Testing Example

```python
def test_type_a_high_value():
    config = ProcessingConfig(ProcessingMode.FAST, flag1=True, flag2=True)
    processor = ItemProcessor(config)

    item = {"id": "1", "type": "A", "value": 100}
    result = processor.process(item)

    assert result.val == 110.0
    assert result.status == Status.HIGH
```

This version is **maintainable**, **testable**, **extensible**, and **self-documenting** while preserving the original behavior.

I'll refactor this code into a clean, testable, and well-structured design. Here's the step-by-step approach:

### Key Problems in Original Code:
1. Deeply nested conditionals making logic hard to follow
2. Multiple responsibilities in one function (processing, validation, output formatting)
3. Magic numbers and hard-coded values
4. No clear separation of business rules from processing logic
5. Brittle error handling
6. Difficulty to test individual components

### Refactored Solution:

```python
import json
from abc import ABC, abstractmethod
from typing import List, Dict, Any, Union

class ProcessingStrategy(ABC):
    """Abstract base class for processing strategies"""
    @abstractmethod
    def process_item(self, item: Dict[str, Any], flags: Dict[str, bool]) -> Dict[str, Any]:
        pass

class FastProcessingStrategy(ProcessingStrategy):
    """Handles 'fast' mode processing rules"""
    TYPE_A_MULTIPLIER = 1.1
    TYPE_B_MULTIPLIER = 0.95
    ADJUSTMENT_MULTIPLIER = 0.9
    HIGH_VALUE_THRESHOLD = 100

    def process_item(self, item: Dict[str, Any], flags: Dict[str, bool]) -> Dict[str, Any]:
        item_type = item.get('type')
        value = item.get('value', 0)

        if item_type == 'A':
            return self._process_type_a(item, value, flags)
        elif item_type == 'B':
            return self._process_type_b(item, value)
        else:
            return self._process_other_type(item, flags)

    def _process_type_a(self, item: Dict[str, Any], value: float, flags: Dict[str, bool]) -> Dict[str, Any]:
        processed_value = value * self.TYPE_A_MULTIPLIER if flags['flag1'] else value

        if processed_value > self.HIGH_VALUE_THRESHOLD:
            if flags['flag2']:
                status = 'high'
            else:
                status = 'adjusted'
                processed_value *= self.ADJUSTMENT_MULTIPLIER
        else:
            status = 'normal'

        return {'id': item['id'], 'val': processed_value, 'status': status}

    def _process_type_b(self, item: Dict[str, Any], value: float) -> Dict[str, Any]:
        processed_value = value * self.TYPE_B_MULTIPLIER
        return {'id': item['id'], 'val': processed_value, 'status': 'discounted'}

    def _process_other_type(self, item: Dict[str, Any], flags: Dict[str, bool]) -> Dict[str, Any]:
        if flags['flag1'] and flags['flag2']:
            return {'id': item['id'], 'val': 0, 'status': 'skip'}
        return {'id': item['id'], 'val': 0, 'status': 'unprocessed'}

class CarefulProcessingStrategy(ProcessingStrategy):
    """Handles 'careful' mode processing rules"""
    def process_item(self, item: Dict[str, Any], flags: Dict[str, bool]) -> Dict[str, Any]:
        try:
            value = float(item.get('value', 0))
            if value < 0:
                raise ValueError("Negative value not allowed")
            return {'id': item['id'], 'val': value, 'status': 'validated'}
        except (ValueError, TypeError):
            return {'id': item['id'], 'val': 0, 'status': 'error'}

class OutputFormatter(ABC):
    """Abstract base class for output formatters"""
    @abstractmethod
    def format(self, results: List[Dict[str, Any]]) -> Union[str, List[Dict[str, Any]]]:
        pass

class JsonFormatter(OutputFormatter):
    """Formats results as JSON string"""
    def format(self, results: List[Dict[str, Any]]) -> str:
        return json.dumps(results)

class CsvFormatter(OutputFormatter):
    """Formats results as CSV string"""
    def format(self, results: List[Dict[str, Any]]) -> str:
        return '\n'.join([f"{r['id']},{r['val']},{r['status']}" for r in results])

class ListFormatter(OutputFormatter):
    """Returns results as list of dictionaries"""
    def format(self, results: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
        return results

class DataProcessor:
    """Main processor class that coordinates strategy and formatting"""
    def __init__(self, mode: str):
        self.strategy = self._get_processing_strategy(mode)
        self.flags = {'flag1': False, 'flag2': True}

    def _get_processing_strategy(self, mode: str) -> ProcessingStrategy:
        strategies = {
            'fast': FastProcessingStrategy(),
            'careful': CarefulProcessingStrategy()
        }
        return strategies.get(mode, FastProcessingStrategy())  # default to fast

    def set_flags(self, flag1: bool = False, flag2: bool = True):
        self.flags = {'flag1': flag1, 'flag2': flag2}

    def process(self, data: List[Dict[str, Any]], output_type: str = 'json') -> Union[str, List[Dict[str, Any]]]:
        results = [self.strategy.process_item(item, self.flags) for item in data]
        return self._get_formatter(output_type).format(results)

    def _get_formatter(self, output_type: str) -> OutputFormatter:
        formatters = {
            'json': JsonFormatter(),
            'csv': CsvFormatter(),
            'list': ListFormatter()
        }
        return formatters.get(output_type, JsonFormatter())  # default to json
```

### Design Decisions Explained:

1. **Strategy Pattern**:
   - Created separate strategy classes (`FastProcessingStrategy`, `CarefulProcessingStrategy`) to encapsulate different processing modes
   - Makes it easy to add new modes without modifying existing code
   - Each strategy has a single responsibility

2. **Factory Methods**:
   - Used in `DataProcessor` to instantiate appropriate strategy and formatter
   - Centralizes creation logic and makes it easy to change implementations

3. **Output Formatting Separation**:
   - Created formatter classes (`JsonFormatter`, `CsvFormatter`, etc.) to handle different output formats
   - Formatting logic is decoupled from processing logic
   - Easy to add new output formats

4. **Eliminated Magic Numbers**:
   - Constants are defined at class level with descriptive names
   - Makes values easier to change and understand

5. **Improved Error Handling**:
   - `CarefulProcessingStrategy` has explicit validation
   - Each strategy handles its own error cases

6. **Type Hints**:
   - Added type annotations for better code clarity and IDE support

7. **Simplified Method Complexity**:
   - Large processing function broken down into smaller, focused methods
   - Each method does one thing and does it well

8. **Configurable Flags**:
   - Flags are managed in one place and passed to strategies
   - Cleaner than multiple boolean parameters

9. **Default Behaviors**:
   - Sensible defaults for strategy and formatter selection

10. **Testability**:
    - Each component can be tested in isolation
    - Mocking is easier with clearly defined interfaces
    - Business rules are encapsulated in strategies

### Usage Example:

```python
data = [{'id': 1, 'type': 'A', 'value': 105}, {'id': 2, 'type': 'B', 'value': 50}]
processor = DataProcessor(mode='fast')
processor.set_flags(flag1=True, flag2=False)
result = processor.process(data, output_type='csv')
print(result)
```

This design is:
- More maintainable (changes to one mode don't affect others)
- Easier to test (components are isolated)
- More extensible (new modes/formats can be added)
- More readable (logic is broken into meaningful components)
- More robust (better error handling and validation)

To refactor this code, we need to move away from "Procedural Spaghetti" (nested `if/else`) and toward a **Strategy Pattern** or **Registry-based** approach.

### The Refactored Code

```python
import json
from abc import ABC, abstractmethod
from typing import List, Dict, Any, Union

# --- Domain Models ---

class ProcessingStrategy(ABC):
    """Abstract base class for different processing modes."""
    @abstractmethod
    def process_item(self, item: Dict[str, Any], flag1: bool, flag2: bool) -> Union[Dict, None]:
        pass

# --- Strategies ---

class FastStrategy(ProcessingStrategy):
    def process_item(self, item: Dict[str, Any], flag1: bool, flag2: bool) -> Union[Dict, None]:
        item_type = item.get('type')
        val = item.get('value', 0)

        if item_type == 'A':
            return self._handle_type_a(item['id'], val, flag1, flag2)
        if item_type == 'B':
            return {'id': item['id'], 'val': val * 0.95, 'status': 'discounted'}
        if flag1 and flag2:
            return {'id': item['id'], 'val': 0, 'status': 'skip'}
        return None

    def _handle_type_a(self, item_id: str, val: float, flag1: bool, flag2: bool) -> Dict:
        adjusted_val = val * 1.1 if flag1 else val
        if adjusted_val > 100:
            if flag2:
                return {'id': item_id, 'val': adjusted_val, 'status': 'high'}
            return {'id': item_id, 'val': adjusted_val * 0.9, 'status': 'adjusted'}
        return {'id': item_id, 'val': adjusted_val, 'status': 'normal'}

class CarefulStrategy(ProcessingStrategy):
    def process_item(self, item: Dict[str, Any], flag1: bool, flag2: bool) -> Dict:
        try:
            val = float(item.get('value', 0))
            if val < 0:
                raise ValueError("Negative value")
            return {'id': item['id'], 'val': val, 'status': 'validated'}
        except (ValueError, TypeError, KeyError):
            return {'id': item['id'], 'val': 0, 'status': 'error'}

# --- Formatters ---

def format_as_csv(data: List[Dict]) -> str:
    return '\n'.join([f"{r['id']},{r['val']},{r['status']}" for r in data])

# --- Main Processor ---

class DataProcessor:
    STRATEGIES = {
        'fast': FastStrategy(),
        'careful': CarefulStrategy()
    }

    FORMATTERS = {
        'json': lambda x: json.dumps(x),
        'csv': format_as_csv,
        'raw': lambda x: x
    }

    def process(self, data: List[Dict], mode: str, flag1: bool = False, 
                flag2: bool = True, output_type: str = 'json'):

        strategy = self.STRATEGIES.get(mode)
        if not strategy:
            raise ValueError(f"Unknown mode: {mode}")

        results = []
        for item in data:
            result = strategy.process_item(item, flag1, flag2)
            if result:
                results.append(result)

        formatter = self.FORMATTERS.get(output_type, self.FORMATTERS['raw'])
        return formatter(results)
```

---

### Design Decisions Explained

#### 1. Strategy Pattern (Decoupling Logic)
The original code used a massive `if mode == 'fast': ... elif mode == 'careful':`. 
- **Decision:** I extracted these into separate classes (`FastStrategy`, `CarefulStrategy`).
- **Why:** If you want to add a `secure` mode later, you simply add a new class instead of making the `process` function even longer. This follows the **Open/Closed Principle**.

#### 2. Flattening Nested Conditionals (Guard Clauses)
The original code had 4-5 levels of indentation (Arrow Code).
- **Decision:** In `FastStrategy`, I used "Guard Clauses" (e.g., `if item_type == 'A': return ...`).
- **Why:** It reduces cognitive load. You can read the logic top-to-bottom without keeping a mental stack of which `else` belongs to which `if`.

#### 3. Registry Pattern for Formatters
The original code imported `json` inside the function and used `if/else` for formatting.
- **Decision:** Created a `FORMATTERS` dictionary.
- **Why:** This makes the output logic extensible. Adding XML or YAML output now only requires adding one line to the dictionary, rather than modifying the core processing loop.

#### 4. Explicit Error Handling
The original code used a "bare except" (`except:`), which is a Python anti-pattern because it catches system interrupts like `KeyboardInterrupt`.
- **Decision:** I changed it to `except (ValueError, TypeError, KeyError)`.
- **Why:** This ensures we only catch expected data-processing errors and allows the program to crash if something truly unexpected happens.

#### 5. Separation of Concerns (Single Responsibility)
The original function did three things: Parsing logic, business math, and output formatting.
- **Decision:** 
    - `DataProcessor` handles the orchestration.
    - `Strategy` classes handle the business logic.
    - `Formatters` handle the presentation.
- **Benefit:** You can now write unit tests for `FastStrategy` without ever touching the JSON/CSV code.

#### 6. Dependency Injection / Registry
The `STRATEGIES` and `FORMATTERS` are stored as class attributes.
- **Benefit:** This makes the code **testable**. In a test environment, you could inject a "MockStrategy" into the `STRATEGIES` dictionary to test the processor in isolation.

